```aiken
import cardano.certificate.{StakePoolRegistration}

fn validate_pool(pool: StakePoolRegistration) -> Bool {
  // Accede directamente al campo vrf
  let vrf_hash = pool.vrf

  // Si necesitas extraer los bytes del hash:
  let VerificationKeyHash(vrf_bytes) = vrf_hash

