use cardano/transaction.{Transaction, InlineDatum}
use aiken/collection/list

pub type OracleDatum {
  price: Int,
}

pub type Redeemer {
  claimed_price: Int,
}

validator price_check {
  spend(
    _datum: Option<Void>,
    redeemer: Redeemer,
    _own_ref: transaction.OutputReference,
    self: Transaction,
  ) -> Bool {
    let oracle_price =
      list.foldr(
        self.reference_inputs,
        None,
        fn(input, acc) {
          when input.output.datum is {
            InlineDatum(raw) ->
              when raw is {
                oracle: OracleDatum -> Some(oracle.price)
                _ -> acc
              }
            _ -> acc
          }
        },
      )
    when oracle_price is {
      Some(p) -> redeemer.claimed_price == p
      None -> False
    }
  }
}

