}

validator single_output {
  spend(
    datum: Option<Datum>,
    _redeemer: Void,
    _own_ref: transaction.OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      Some(d) -> {
        let count =
          list.count(self.outputs, fn(o) {
            when o.address.payment_credential is {
              transaction.VerificationKey(vk) -> vk == d.recipient
              _ -> False
