use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use aiken/interval
use cardano/assets
use cardano/transaction.{Transaction, Output}

validator full_check(
  owner: VerificationKeyHash,
  policy_id: PolicyId,
  asset_name: AssetName,
  deadline: Int,
) {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let signed = list.has(self.extra_signatories, owner)
    let in_time = interval.is_entirely_before(self.validity_range, deadline)
    let has_token =
      list.any(
        self.outputs,
        fn(output: Output) {
          assets.quantity_of(output.value, policy_id, asset_name) >= 1
        },
      )
    signed && in_time && has_token
  }
}

