validator multisig_threshold {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    _own_ref: cardano/transaction.OutputReference,
    self: Transaction,
  ) -> Bool {
    // Filtra los firmantes presentes que están en la lista autorizada
    let present_authorized =
      list.filter(
        authorized_keys,
        fn(key: VerificationKeyHash) {
          list.has(self.extra_signatories, key)
        },
      )
    // Requiere al menos 2 firmantes autorizados
    list.length(present_authorized) >= 2
  }
}
```

**Consideraciones de seguridad:**
- Usa `self.extra_signatories` (campo verificado del tipo `Transaction`).
- `list.has` compara por igualdad estructural, correcto para `VerificationKeyHash`.
- No uses `list.any` anidado innecesariamente; `list.filter` + `list.length` es claro y eficiente.

`list.filter_map` combines filtering and mapping into a single pass over a list. It applies a predicate function to each element that returns an `Option<b>`: if the result is `Some(value)`, the value is included in the output list; if it is `None`, the element is discarded.

This is more efficient than chaining `list.filter` and `list.map` because it only traverses the list once.

Signature:
```aiken
pub fn filter_map(self: List<a>, predicate: fn(a) -> Option<b>) -> List<b>
```

Example from the docs:
```aiken
use aiken/collection/list

let transform = fn(x) {
  if x % 2 == 0 {
    None
  } else {
    Some(3 * x)
  }
}

list.filter_map([1, 2, 3], transform) == [3, 9]
```

Here, `2` is even so it maps to `None` and is dropped; `1` and `3` are odd so they map to `Some(3)` and `Some(9)` respectively.

```aiken
use cardano/assets
use cardano/transaction.{Transaction, Input}
use aiken/collection/list

validator threshold_check(policy_id: assets.PolicyId, min_total: Int) {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    _own_ref: transaction.OutputReference,
    self: Transaction,
  ) -> Bool {
    let qualifying_lovelace: List<Int> =
      list.filter_map(
        self.inputs,
        fn(input: Input) -> Option<Int> {
          let val = input.output.value
          if assets.quantity_of(val, policy_id, assets.ada_asset_name) > 0 {
            Some(assets.lovelace_of(val))
          } else {
            None
          }
        },
      )

    let total = list.foldl(qualifying_lovelace, 0, fn(amt, acc) { acc + amt })
    total >= min_total
  }

  else(_) {
    fail
  }
}
```

