    let allowed_names = list.slice(all_asset_names, from: 0, to: 2)
    let minted_tokens = assets.tokens(self.mint, policy_id)
    let minted_names =
      minted_tokens
        |> assets.to_dict
        |> fn(_) { list.map(assets.flatten(self.mint), fn(t) { t.2nd }) }
    list.all(minted_names, fn(name) { list.has(allowed_names, name) })
  }
}
```

