      list.foldl2(
        self.inputs,
        0,   // zero_a: total lovelace
        0,   // zero_b: count of inputs > 5 ADA
        fn(input: Input, total: Int, cnt: Int, return) {
          let lv = assets.lovelace_of(input.output.value)
          let new_cnt =
            if lv > 5_000_000 {
              cnt + 1
            } else {
              cnt
            }
          return(total + lv, new_cnt)
        },
        fn(total, cnt) { (total, cnt) },
      )

    total_lovelace >= 10_000_000 && big_input_count >= 1
  }
}
```

