fn validity_in_range(tx: Transaction, lo: Int, hi: Int) -> Bool {
  let allowed = interval.between(lo, hi)
  // La intersección de la validez con la ventana permitida debe
  // ser igual a la validez original, es decir, estar totalmente contenida.
  interval.includes(allowed, tx.validity_range)
