use aiken/math
use aiken/collection/list
use cardano/assets
use cardano/transaction.{Transaction}

validator power_of_two_mint {
  mint(
    _redeemer: Void,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    // Sum all quantities minted under this policy
    let total =
      self.mint
        |> assets.tokens(_, policy_id)
        |> assets.to_dict
        |> fn(d) {
             list.foldl(
               assets.tokens(self.mint, policy_id)
                 |> fn(_) { [] },
               0,
               fn(_, acc) { acc },
             )
           }
    // Simpler: flatten and sum
    let minted_pairs =
      assets.flatten(self.mint)
        |> list.filter(fn(triple) {
             let (pid, _, _) = triple
             pid == policy_id
           })
    let total_minted =
      list.foldl(
        minted_pairs,
        0,
        fn(triple, acc) {
          let (_, _, qty) = triple
          acc + qty
        },
      )
    // Check total is a power of 2
    total_minted > 0 && math.pow2(math.log2(total_minted)) == total_minted
  }
}
