use cardano/transaction.{OutputReference, Transaction}

validator starts_with_ab {
  spend(
    _datum: Option<Data>,
    redeemer: ByteArray,
    _own_ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    // Build the single-byte prefix #"ab"
    let prefix = bytearray.push(#"", 0xab)
    // Check that the redeemer starts with that byte
    bytearray.take(redeemer, 1) == prefix
  }
}
```

Usamos `bytearray.push(#"", 0xab)` para construir `#"ab"` dinámicamente, y luego comparamos el primer byte del redeemer con ese prefijo. En PlutusV3, el valor `0xab` (171) está dentro del rango válido 0–255, por lo que no habrá error de desbordamiento.

