output:
```aiken
use cardano/assets

fn check_min_ada(v: assets.Value, min: Int) -> Bool {
  assets.quantity_of(v, assets.ada_policy_id, assets.ada_asset_name) >= min
}
```

Using the named constants `assets.ada_policy_id` and `assets.ada_asset_name` instead of raw `""` literals makes the intent explicit — the reader immediately understands the code is querying Ada (lovelace), not an unnamed token with an empty policy/asset name. Alternatively, you can simplify further with the dedicated helper:

```aiken
use cardano/assets

fn check_min_ada(v: assets.Value, min: Int) -> Bool {
  assets.lovelace_of(v) >= min
}
```

```aiken
use cardano/assets.{AssetName, PolicyId}
use cardano/transaction.{Transaction}

validator my_token_policy {
  mint(redeemer: Void, policy_id: PolicyId, self: Transaction) -> Bool {
    let allowed_name: AssetName = "MY_TOKEN"
    let minted_tokens = assets.tokens(self.mint, policy_id)
    // Every minted asset name under this policy must equal the allowed name
    minted_tokens
      |> assets.to_dict
      // tokens() returns a Dict<AssetName, Int>; check all names match
      |> fn(d) {
           let names = d |> dict_keys
           list.all(names, fn(name) { name == allowed_name })
         }
  }
}
```

> **Note:** The simpler idiomatic approach uses `assets.tokens/2` which returns a `Dict<AssetName, Int>` for a given policy, then verifies only the expected asset name has a non-zero quantity:

```aiken
use cardano/assets.{AssetName, PolicyId}
use cardano/transaction.{Transaction}
use aiken/collection/list

validator my_token_policy {
  mint(redeemer: Void, policy_id: PolicyId, self: Transaction) -> Bool {
    let allowed_name: AssetName = "MY_TOKEN"
    let minted = assets.tokens(self.mint, policy_id)
    // flatten the minted value for this policy and check every name
    assets.flatten(self.mint)
      |> list.all(
           fn(triple) {
             let (pid, name, _qty) = triple
             pid != policy_id || name == allowed_name
           },
         )
  }
}
```

Use `assets.quantity_of/3` which takes a `Value`, a `PolicyId`, and an `AssetName` and returns the `Int` quantity (0 if absent):

```aiken
use cardano/assets.{AssetName, PolicyId}
use cardano/transaction.{Output, Transaction}

// Example inside a spend validator
validator check_token_quantity {
  spend(
    datum: Option<Void>,
    redeemer: Void,
    own_ref: transaction.OutputReference,
    self: Transaction,
  ) -> Bool {
    let policy_id: PolicyId = #"deadbeef00112233445566778899aabbccddeeff00112233445566778899aabb"
    let asset_name: AssetName = "MY_TOKEN"
    let required_qty: Int = 1

    // Find the input being spent and check its value
    expect Some(own_input) = transaction.find_input(self.inputs, own_ref)
    let qty = assets.quantity_of(own_input.output.value, policy_id, asset_name)
    qty >= required_qty
  }
}
```

`assets.quantity_of` is the canonical way to inspect how many units of a specific `(PolicyId, AssetName)` pair exist in a `Value`.

```aiken
use cardano/assets.{AssetName, PolicyId}
use cardano/transaction.{OutputReference, Transaction}

const nft_policy_id: PolicyId =
  #"deadbeef00112233445566778899aabbccddeeff00112233445566778899aabb"

const nft_asset_name: AssetName = "nft_001"

validator nft_gate {
  spend(
    datum: Option<Void>,
    redeemer: Void,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    // Comprueba que alguna entrada de la transacción contiene el NFT requerido
    list.any(
      self.inputs,
      fn(input) {
        assets.quantity_of(
          input.output.value,
          nft_policy_id,
          nft_asset_name,
        ) >= 1
      },
    )
  }
}
```

Este validador usa `assets.quantity_of/3` para verificar que al menos una entrada contiene el NFT identificado por `nft_policy_id` y `nft_asset_name` (`AssetName` es simplemente un alias de `ByteArray`).

```aiken
use cardano/assets

fn has_min_ada(v: assets.Value) -> Bool {
  // Ada is identified by the empty policy id and empty asset name
  let lovelace =
    assets.quantity_of(v, assets.ada_policy_id, assets.ada_asset_name)
  lovelace >= 2_000_000
}
```

`assets.ada_policy_id` is `""` and `assets.ada_asset_name` is `""`, so `quantity_of` looks up the ADA entry in the `Value`. Alternatively you can use the convenience helper `assets.lovelace_of(v)` which does the same thing under the hood.

```aiken
use cardano/assets
use cardano/transaction.{Transaction}
use aiken/collection/list

validator no_ada_name_mint {
  mint(redeemer: Data, policy_id: assets.PolicyId, self: Transaction) -> Bool {
    // Collect all asset names being minted under this policy
    let minted_names =
      assets.tokens(self.mint, policy_id)
        |> assets.to_dict  // Dict<AssetName, Int> — unwrap via tokens directly
    // Ensure none of the minted asset names equal ada_asset_name ("")
    let names: List<assets.AssetName> =
      assets.flatten(assets.from_asset(policy_id, "", 0))
        |> list.map(fn(triple) { let (_, name, _) = triple; name })
    // Simpler: check directly on the flattened mint value
    assets.flatten(self.mint)
      |> list.all(
          fn(triple) {
            let (pid, asset_name, _qty) = triple
            if pid == policy_id {
              asset_name != assets.ada_asset_name
            } else {
              True
            }
          },
        )
  }
}
```

The key check is `asset_name != assets.ada_asset_name` (i.e. `asset_name != ""`). `assets.flatten` returns `List<(PolicyId, AssetName, Int)>` so we can pattern-match each triple and reject any entry whose asset name is the empty byte array.

```aiken
use cardano/assets

/// Retorna True si el Value solo contiene ADA (lovelace), sin tokens nativos.
fn only_lovelace(v: assets.Value) -> Bool {
  // without_lovelace elimina la entrada de ADA del Value.
  // Si el resultado es zero, no hay tokens nativos.
  assets.is_zero(assets.without_lovelace(v))
}
```

**Explicación:**
- `assets.without_lovelace(v)` devuelve un `Value` idéntico pero sin la entrada correspondiente a `(ada_policy_id, ada_asset_name)` (es decir, sin ADA).
- `assets.is_zero(...)` comprueba que el `Value` resultante esté vacío, lo que significa que no hay ningún token nativo presente.
- Si el `Value` original solo tenía lovelace, el valor sin lovelace será `zero` y la función retornará `True`.

Sí, es seguro y es el patrón correcto. `assets.ada_asset_name` es simplemente la constante `""` (un `ByteArray` vacío), por lo que comparar `asset_name != assets.ada_asset_name` es equivalente a `asset_name != ""`.

**Consideraciones de seguridad:**

1. **Ada no puede mintearse** — El protocolo de Cardano impide físicamente mintear Ada en ninguna transacción. Sin embargo, un atacante podría intentar crear un token bajo *tu* `PolicyId` con `AssetName = ""`, lo que podría confundirse con Ada en lógica de contrato descuidada.

2. **Validación recomendada en el validador de minteo:**

```aiken
use cardano/assets
use cardano/transaction.{Transaction}

validator safe_minter {
  mint(redeemer: Data, policy_id: assets.PolicyId, self: Transaction) -> Bool {
    // Rechazar si algún token minteado bajo este policy tiene nombre vacío
    let no_empty_name =
      assets.flatten(self.mint)
        |> list.all(
            fn(triple) {
              let (pid, name, _) = triple
              if pid == policy_id {
                name != assets.ada_asset_name
              } else {
                True
              }
            },
          )
    no_empty_name
  }
}
```

3. **No confundir** `ada_asset_name` con `ada_policy_id` — ambos son `""`, pero se usan en posiciones distintas. Intercambiarlos en `quantity_of` devolvería 0 en lugar de fallar, lo que podría introducir bugs silenciosos.

```aiken
use cardano/assets
use cardano/transaction.{Transaction}

validator control_token_mint {
  mint(redeemer: Void, policy_id: assets.PolicyId, self: Transaction) -> Bool {
    let expected_value = assets.from_asset(policy_id, "ControlToken", 1)
    self.mint == expected_value
  }
}
```

`assets.from_asset(policy_id, "ControlToken", 1)` constructs the exact `Value` expected in `self.mint`. Comparing `self.mint == expected_value` ensures exactly 1 unit of `"ControlToken"` under this policy is minted — no more, no less.

`assets.from_lovelace(quantity)` construye un `Value` que contiene únicamente ADA (lovelace), usando el `ada_policy_id` (`""`) y el `ada_asset_name` (`""`) por convención.

`assets.from_asset(policy_id, asset_name, quantity)` construye un `Value` para cualquier token nativo identificado por su `PolicyId` (28 bytes) y su `AssetName` (ByteArray de hasta 32 bytes).

Ejemplos:
```aiken
use cardano/assets

// Solo ADA
let ada_value = assets.from_lovelace(2_000_000)

// Token nativo personalizado
let token_value = assets.from_asset(#"deadbeef", "MiToken", 50)
```

Ambas devuelven un `Value`, pero `from_asset` es para tokens nativos que no son ADA.

```aiken
use cardano/assets
use cardano/transaction.{Transaction}

validator nft_burn {
  mint(redeemer: Void, policy_id: assets.PolicyId, self: Transaction) -> Bool {
    let burn_value = assets.from_asset(policy_id, "MyNFT", -1)
    self.mint == burn_value
  }
}
```

Usar una cantidad de `-1` en `assets.from_asset` representa la quema del token. Al comparar `self.mint == burn_value`, se garantiza que la transacción únicamente quema exactamente 1 NFT llamado `"MyNFT"` bajo esa política, sin permitir acuñaciones adicionales.

```aiken
use cardano/assets

let lovelace_val = assets.from_lovelace(2_000_000)
let token_val = assets.from_asset(#"cafe", "Gold", 10)
let combined = assets.merge(lovelace_val, token_val)
```

`assets.from_asset(#"cafe", "Gold", 10)` constructs a `Value` with 10 Gold tokens. `assets.from_lovelace(2_000_000)` constructs a `Value` with 2 ADA. `assets.merge/2` combines both into a single `Value` containing both the lovelace and the custom token.

```aiken
use cardano/assets
use cardano/transaction.{Transaction}

validator redeemer_mint_validator {
  mint(redeemer: Pairs<ByteArray, Pairs<ByteArray, Int>>, policy_id: ByteArray, self: Transaction) -> Bool {
    // from_asset_list will halt if the list is malformed (duplicates, bad order, zero qty)
    let expected_value = assets.from_asset_list(redeemer)

    // Verify the minted value matches what was declared in the redeemer
    let minted = self.mint
    minted == expected_value
  }
}
```

`assets.from_asset_list` acts as an implicit guard: if the redeemer list violates any invariant (duplicate `PolicyId`, duplicate `AssetName`, non-ascending lexicographic order of asset names, or a zero quantity), the script halts before the equality check is even reached.

```aiken
use cardano/assets
use cardano/transaction.{Transaction, OutputReference}
use cardano/transaction

type AssetDatum {
  expected_assets: Pairs<ByteArray, Pairs<ByteArray, Int>>
}

validator asset_check_validator {
  spend(
    datum: Option<AssetDatum>,
    _redeemer: Void,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        // from_asset_list falla en ejecución si la lista del datum es inválida
        let expected_value = assets.from_asset_list(d.expected_assets)

        // Buscar la salida propia y comparar su valor
        let own_input = transaction.find_input(self.inputs, own_ref)
        when own_input is {
          None -> False
          Some(input) ->
            assets.without_lovelace(input.output.value) == expected_value
        }
      }
    }
  }
}
```

`assets.from_asset_list` actúa como una barrera de validación: si el datum contiene políticas duplicadas, nombres de activos duplicados, orden lexicográfico incorrecto o cantidades nulas, el script se detiene automáticamente antes de cualquier comparación.

