```aiken
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}

validator auth_mint(
  auth_policy: PolicyId,
  auth_asset: ByteArray,
  required_signer: VerificationKeyHash,
) {
  mint(
    _redeemer: Void,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let signed =
      list.has(self.extra_signatories, required_signer)

    let first_output_has_auth_nft =
      when list.head(self.outputs) is {
        None -> False
        Some(out) ->
          assets.has_nft(out.value, auth_policy, auth_asset)
      }

    let minted_exactly_one =
      assets.quantity_of(self.mint, policy_id, "") == 1

    signed && first_output_has_auth_nft && minted_exactly_one
  }

  else(_) -> Bool {
    False
  }
}
```

El validador verifica tres condiciones:
1. El firmante requerido está en `self.extra_signatories`.
2. El primer output contiene el NFT de autorización (`assets.has_nft`).
3. Solo se acuña exactamente 1 token con esta póliza.

