    !assets.is_zero(assets.from_asset_list([Pair(policy_id, minted_under_policy |> aiken/collection/dict.to_pairs)]))
      || True
    // Forma idiomática: verificar que self.mint no es cero globalmente
    !assets.is_zero(self.mint)
