`assets.tokens(self.mint, policy_id)` scopes the minted value down to only this policy's tokens, making it easy to assert both the name and quantity.

```aiken
use cardano/assets
use cardano/transaction.{Output, OutputReference, Transaction, find_input}
use aiken/collection/dict

pub type Datum {
  required_policy: ByteArray,
}

validator policy_gating {
  spend(
    datum: Option<Datum>,
    _redeemer: Void,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    expect Some(input) = find_input(self.inputs, own_ref)
    let tok = assets.tokens(input.output.value, d.required_policy)
    !dict.is_empty(tok)
