    },
  } = validity_range
  when (lower_bound_type, upper_bound_type) is {
    (interval.NegativeInfinity, interval.PositiveInfinity) -> Always
    (interval.NegativeInfinity, interval.Finite(upper_int)) ->
      FromNegInf { upper: resolve_upper(upper_int, upper_is_inclusive) }
    (interval.Finite(init_lower_int), interval.Finite(init_upper_int)) -> {
      let lower = resolve_lower(init_lower_int, lower_is_inclusive)
      let upper = resolve_upper(init_upper_int, upper_is_inclusive)
      if lower >= upper {
        InvalidRange
      } else {
        ClosedRange { lower, upper }
      }
    }
    (interval.Finite(init_lower_int), interval.PositiveInfinity) ->
      ToPosInf { lower: resolve_lower(init_lower_int, lower_is_inclusive) }
    _ -> InvalidRange
  }
}

validator after_time_mint {
  mint(redeemer: Int, _policy_id: PolicyId, self: Transaction) -> Bool {
    when normalize_time_range(self.validity_range) is {
      ToPosInf { lower } -> lower >= redeemer
      _ -> False
    }
  }
}
```

Las funciones `resolve_lower` y `resolve_upper` convierten un límite entero con su bandera de inclusividad en un único entero siempre inclusivo:

```aiken
fn resolve_lower(init_lower: Int, is_inclusive: Bool) -> Int {
  if is_inclusive {
    init_lower        // ya es inclusivo, no hay cambio
  } else {
    init_lower + 1    // exclusivo → se sube 1 para hacerlo inclusivo
  }
}

fn resolve_upper(init_upper: Int, is_inclusive: Bool) -> Int {
  if is_inclusive {
    init_upper        // ya es inclusivo, no hay cambio
  } else {
    init_upper - 1    // exclusivo → se baja 1 para hacerlo inclusivo
  }
}
```

**Razonamiento matemático:**
- Para el límite inferior: el intervalo `(4, ...]` (exclusivo en 4) es equivalente a `[5, ...]` (inclusivo en 5). Por eso se suma 1.
- Para el límite superior: el intervalo `[..., 11)` (exclusivo en 11) es equivalente a `[..., 10]` (inclusivo en 10). Por eso se resta 1.

Tras aplicar estas funciones, todos los límites finitos en `NormalizedTimeRange` son siempre inclusivos, eliminando la ambigüedad de representación.

```aiken
use cardano/assets

const min_lovelace = 2_000_000

fn make_node_value(script_hash: PolicyId, asset_name: ByteArray) -> Value {
  let lovelace_value = assets.from_lovelace(min_lovelace)
  let state_nft = assets.from_asset(script_hash, asset_name, 1)
  assets.merge(lovelace_value, state_nft)
}
```

This mirrors the pattern used in the linked-list tests:
- `assets.from_lovelace/1` creates a lovelace-only `Value`.
- `assets.from_asset/3` creates a single-token `Value`.
- `assets.merge/2` combines them into the final node value.

```aiken
use cardano/assets
use cardano/transaction.{Output}

fn output_has_node_nft(
  output: Output,
  policy_id: assets.PolicyId,
  asset_name: assets.AssetName,
) -> Bool {
  assets.quantity_of(output.value, policy_id, asset_name) == 1
}
```

- `assets.quantity_of/3` returns the integer quantity of a specific `(PolicyId, AssetName)` pair inside a `Value`; it returns `0` if the token is absent.
- Comparing to `1` enforces that exactly one NFT is present — no more, no less.
- `output.value` is the direct field access on `Output`; no helper function is needed.

This mirrors how the linked-list test suite constructs node values with `assets.from_asset(script_hash, tn, 1)` and then verifies their presence.

