  b: Int
}

validator linear_check {
  spend(
    datum: Option<Params>,
    redeemer: Int,
    _own_ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      Some(params) -> redeemer * params.a + params.b > 0
      None -> False
    }
  }
}
```

