  mint(_r: Data, policy_id: PolicyId, self: Transaction) {
    let Transaction { inputs, mint, .. } = self

    expect Some(first_input) = list.at(inputs, 0)

    // Pattern match asserts: exactly ONE asset name is minted under this
    // policy_id. Any other number of asset names causes the validator to fail.
    expect [Pair(asset_name, quantity)] =
      mint
        |> assets.tokens(policy_id)
        |> dict.to_pairs()

    let expected_token_name =
      first_input.output_reference
        |> cbor.serialise
        |> blake2b_256

    // The asset name must equal the hash of the first input's output reference,
    // and exactly 1 token must be minted — no more, no less.
    asset_name == expected_token_name && quantity == 1
  }

  else(_) {
    fail
  }
}
