use aiken/collection/list
use aiken/crypto.{Blake2b_224, Hash, VerificationKey}
use cardano/address
use cardano/assets.{lovelace_of, merge}
use cardano/transaction.{Output, OutputReference, Transaction}

type VerificationKeyHash = Hash<Blake2b_224, VerificationKey>

pub type DatumSwap {
  beneficiary: VerificationKeyHash,
  price: Int,
}

validator exploitable_swap {
  spend(
    optional_datum: Option<DatumSwap>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    expect Some(datum) = optional_datum
    let beneficiary = address.from_verification_key(datum.beneficiary)
    let user_outputs =
      list.filter(
        self.outputs,
        fn(output) { output.address == beneficiary },
      )
    let value_paid =
      list.foldl(
        user_outputs,
        assets.zero,
        fn(output, total) { merge(output.value, total) },
      )
    (lovelace_of(value_paid) >= datum.price)?
  }
}
```

**Why it is vulnerable:** Every spend execution of this validator scans *all* transaction outputs for payments to the beneficiary. If two UTxOs with the same beneficiary and price are spent in one transaction, a single 5 ADA output satisfies both validations — the attacker pays once but claims both UTxOs.

```aiken
use aiken/collection/list
use aiken/crypto.{Blake2b_224, Hash, VerificationKey}
use cardano/address
use cardano/assets.{lovelace_of, merge}
use cardano/transaction.{Output, OutputReference, Transaction}

type VerificationKeyHash = Hash<Blake2b_224, VerificationKey>

pub type DatumSwap {
  beneficiary: VerificationKeyHash,
  price: Int,
}

validator exploitable_swap {
  spend(
    optional_datum: Option<DatumSwap>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    expect Some(datum) = optional_datum
    let beneficiary = address.from_verification_key(datum.beneficiary)
    let user_outputs =
      list.filter(
        self.outputs,
        fn(output) { output.address == beneficiary },
      )
    let value_paid =
      list.foldl(
        user_outputs,
        assets.zero,
        fn(output, total) { merge(output.value, total) },
      )
    (lovelace_of(value_paid) >= datum.price)?
  }
}
```

**Nota de seguridad:** Este validador es intencionalmente vulnerable a Double Satisfaction. No debe usarse en producción sin mitigaciones adicionales que aseguren que cada output solo sea contabilizado una vez por cada input que se está gastando.

```aiken
use aiken/collection/list
use aiken/crypto.{Blake2b_224, Hash, VerificationKey}
use cardano/address
use cardano/assets.{lovelace_of}
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}

type VerificationKeyHash = Hash<Blake2b_224, VerificationKey>

pub type DatumSwap {
  beneficiary: VerificationKeyHash,
  price: Int,
}

validator swap {
  spend(
    optional_datum: Option<DatumSwap>,
    _redeemer: Data,
    own_ref: OutputReference,
    self: Transaction,
  ) {
    expect Some(datum) = optional_datum
    let beneficiary_addr = address.from_verification_key(datum.beneficiary)

    // Filter outputs whose inline datum equals this input's OutputReference (the tag).
    let tagged_outputs =
      list.filter(
        self.outputs,
        fn(output: Output) {
          when output.datum is {
            InlineDatum(output_datum) ->
              // Soft-cast: ignore outputs with a different datum shape.
              if output_datum == (own_ref: Data) {
                True
              } else {
                False
              }
            _ -> False
          }
        },
      )

    // Exactly one tagged output must exist.
    expect [tagged_output] = tagged_outputs

    // The tagged output must go to the beneficiary with at least the price.
    tagged_output.address == beneficiary_addr && lovelace_of(tagged_output.value) >= datum.price
  }
}
```

