output:
The naive version is vulnerable to double-satisfaction: the same output to the beneficiary could satisfy multiple concurrent input validations. The fix is to tag each output with the unique `own_ref` of the input being validated.

```aiken
use aiken/collection/list
use aiken/crypto.{Blake2b_224, Hash, VerificationKey}
use cardano/address
use cardano/assets.{lovelace_of}
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}

type VerificationKeyHash = Hash<Blake2b_224, VerificationKey>

pub type DatumSwap {
  beneficiary: VerificationKeyHash,
  price: Int,
}

validator swap {
  spend(
    optional_datum: Option<DatumSwap>,
    _redeemer: Data,
    own_ref: OutputReference,
    self: Transaction,
  ) {
    expect Some(datum) = optional_datum
    let beneficiary_addr = address.from_verification_key(datum.beneficiary)

    // Find the single output tagged with this input's OutputReference.
    let tagged_outputs =
      list.filter(
        self.outputs,
        fn(output: Output) {
          when output.datum is {
            InlineDatum(d) ->
              if d == (own_ref: Data) {
                True
              } else {
                False
              }
            _ -> False
          }
        },
      )

    // Exactly one tagged output must exist, addressed to the beneficiary
    // with at least the required price.
    expect [tagged_output] = tagged_outputs
    tagged_output.address == beneficiary_addr && lovelace_of(tagged_output.value) >= datum.price
  }
}
```

**Key changes:**
- The output is now identified by its inline datum matching `own_ref` (unique per input), not just by the destination address.
- `expect [tagged_output] = tagged_outputs` enforces exactly one match, preventing reuse across executions.
- The soft-cast inside the `when` expression ensures outputs with unrelated datums are silently ignored instead of crashing the validator.

use aiken/collection/dict
use aiken/collection/list
use cardano/address.{Script}
use cardano/assets.{PolicyId, policies}
use cardano/transaction.{InlineDatum, OutputReference, Transaction}

validator counter_stt(utxo_ref: OutputReference) {
  mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) {
    let Transaction { inputs, outputs, mint, .. } = self
    expect [Pair(_asset_name, quantity)] =
      mint
        |> assets.tokens(policy_id)
        |> dict.to_pairs()
    let is_output_consumed =
      list.any(inputs, fn(input) { input.output_reference == utxo_ref })
    expect Some(nft_output) =
      list.find(outputs, fn(output) {
        list.has(policies(output.value), policy_id)
      })
    expect InlineDatum(datum) = nft_output.datum
    expect counter: Int = datum
    is_output_consumed? && (1 == quantity)? && counter == 0
  }

  else(_) {
    fail
  }
}

