    expect [Pair(_asset_name, quantity)] =
      mint
        |> assets.tokens(policy_id)
        |> dict.to_pairs()
    let is_output_consumed =
      list.any(inputs, fn(input) { input.output_reference == utxo_ref })
    expect Some(nft_output) =
      list.find(outputs, fn(output) {
        list.has(policies(output.value), policy_id)
      })
    expect InlineDatum(datum) = nft_output.datum
    expect counter: Int = datum
    is_output_consumed? && (1 == quantity)? && counter == 0
  }

  spend(datum_opt: Option<Int>, _redeemer: Data, own_ref: OutputReference, self: Transaction) {
    let Transaction { inputs, outputs, .. } = self
    expect Some(input_datum) = datum_opt
    // Derive the policy_id from the script hash (same as own address credential)
    expect Some(own_input) =
      list.find(inputs, fn(i) { i.output_reference == own_ref })
    let script_credential = own_input.output.address.payment_credential
    expect Script(policy_id) = script_credential
    // Find the output that carries the STT NFT
    expect Some(nft_output) =
      list.find(outputs, fn(output) {
        list.has(policies(output.value), policy_id)
      })
    expect InlineDatum(out_datum) = nft_output.datum
    expect output_counter: Int = out_datum
    output_counter == input_datum + 1
  }

  else(_) {
    fail
  }
}

