use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}

validator simple_withdrawal {
  withdraw(_redeemer: Void, account: Credential, self: Transaction) -> Bool {
    let required_signer: VerificationKeyHash = #"abcdef1234"

    let is_signed = list.has(self.extra_signatories, required_signer)

