```aiken
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use aiken/interval
use cardano/assets.{AssetName, PolicyId}
use cardano/transaction.{Transaction}

pub type MetadataAnchorParams {
  authority_key: VerificationKeyHash,
  allowed_asset_names: List<AssetName>,
  window_start: Int,
  window_end: Int,
}

validator metadata_anchor(params: MetadataAnchorParams) {
  mint(redeemer: Void, policy_id: PolicyId, self: Transaction) -> Bool {
    let signed_by_authority =
      list.has(self.extra_signatories, params.authority_key)

    let mint_window = interval.between(params.window_start, params.window_end)

    let within_window =
      interval.includes(mint_window, self.validity_range)

    let all_minted_are_allowed =
      assets.tokens(self.mint, policy_id)
        |> assets.flatten(assets.from_asset_list([]))

    let minted_tokens = assets.flatten(self.mint)

    let only_valid_mints =
      list.all(
        minted_tokens,
        fn(triple) {
          let (pid, aname, qty) = triple
          if pid == policy_id {
            list.has(params.allowed_asset_names, aname) && qty == 1
          } else {
            True
          }
        },
      )

    signed_by_authority && within_window && only_valid_mints
  }

  else(_) {
    fail
  }
}
```

This policy enforces:
- Only the authority key can trigger minting (trust model from CIP-0026).
- Minting is only valid within the specified time window (`interval.includes` checks that the tx validity range is fully within the mint window).
- Only pre-approved asset names can be minted, each with quantity exactly 1 (NFT semantics for metadata anchoring).

```aiken
use cardano/assets
use cardano/transaction.{OutputReference, Transaction, find_input}
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}

/// One-shot CIP-0027 royalty token minting policy.
/// `utxo_ref`  – the UTxO that must be consumed to mint (ensures one-shot).
/// `owner_pkh` – the key that must sign the transaction.
validator royalty_policy(utxo_ref: OutputReference, owner_pkh: VerificationKeyHash) {
  mint(redeemer: Void, policy_id: PolicyId, self: Transaction) -> Bool {
    // 1. The seeding UTxO must be spent, guaranteeing one-shot behaviour.
    let seeding_input_present =
      find_input(self.inputs, utxo_ref) |> fn(opt) { opt != None }

    // 2. Owner must sign.
    let signed_by_owner =
      list.has(self.extra_signatories, owner_pkh)

    // 3. Exactly one token with empty asset name is minted; quantity == 1.
    let minted_tokens =
      assets.tokens(self.mint, policy_id)

    let correct_mint =
      minted_tokens == [Pair("", 1)]

    seeding_input_present && signed_by_owner && correct_mint
  }

  else(_) {
    False
  }
}
```

**How it satisfies CIP-0027 rules:**
- The `utxo_ref` parameter is a specific unspent output; once consumed it can never be consumed again, making this a one-shot policy. This matches the rule that only the first minted instructions are honored.
- The empty asset name (`""`) matches the CIP-0027 convention of an *unnamed* token.
- The quantity check (`== 1`) prevents minting multiple royalty tokens.
- `list.has(self.extra_signatories, owner_pkh)` ensures only the legitimate creator can trigger the mint.

```aiken
use cardano/assets
use cardano/transaction.{OutputReference, Transaction, Output}
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use cardano/address.{Address, VerificationKey}

/// Redeemer carries the agreed sale price in lovelace.
pub type SaleRedeemer {
  sale_price: Int,
}

/// Spend validator enforcing CIP-0027 royalty payment.
/// `royalty_bps`     – royalty rate in basis points (e.g. 500 = 5%).
/// `royalty_vkh`     – verification key hash of the royalty recipient.
validator royalty_spend(royalty_bps: Int, royalty_vkh: VerificationKeyHash) {
  spend(
    _datum: Option<Void>,
    redeemer: SaleRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let required_lovelace = redeemer.sale_price * royalty_bps / 10000

    // Find any output paying at least `required_lovelace` to the royalty address.
    let royalty_paid =
      list.any(
        self.outputs,
        fn(output: Output) -> Bool {
          when output.address.payment_credential is {
            VerificationKey(vkh) ->
              vkh == royalty_vkh && assets.lovelace_of(output.value) >= required_lovelace
            _ -> False
          }
        },
      )

    royalty_paid
  }

  else(_) {
    False
  }
}
```

**Notas:**
- `royalty_bps / 10000` convierte puntos básicos a fracción; la multiplicación se hace primero para evitar truncamiento a cero.
- `assets.lovelace_of(output.value)` obtiene el ADA de la salida usando la API verificada de `cardano/assets`.
- `output.address.payment_credential` se usa para identificar al destinatario — marcado `PLAUSIBLE_NEEDS_CHECK` porque el acceso a campos de `Address` puede variar según la versión del compilador.

