```

**Key points:**
- In Aiken v3, the `spend` handler receives `datum: Option<MyDatum>` directly — the runtime automatically unwraps the inline datum (or datum-hash-resolved datum) into the typed `Option`.
- If the output carries an `InlineDatum`, its `Data` is decoded into `MyDatum` and passed as `Some(d)`.
- If no datum is present, `datum` is `None` and we return `False`.
- There is no need to manually pattern-match on `DatumHash` / `InlineDatum` in the handler; Aiken handles the resolution transparently.

En Aiken, el tipo `Datum` definido en `cardano/transaction` tiene dos constructores:

```aiken
pub type Datum
  DatumHash(DataHash)  // solo hash del datum
  InlineDatum(Data)    // datum completo en línea (CIP-0032)
```

Puedes inspeccionar el campo `datum` de un `Output` con un `when` para distinguir ambos casos:

```aiken
use cardano/transaction.{Output, InlineDatum, DatumHash, OutputReference, Transaction}
use aiken/collection/list

validator check_inline_datum {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    // Busca el primer output que tenga un inline datum
    let has_inline =
      list.any(
        self.outputs,
        fn(output: Output) -> Bool {
          when output.datum is {
            InlineDatum(_) -> True
            DatumHash(_) -> False
            _ -> False
          }
        },
      )
    has_inline
  }
}
```

**Notas:**
- `output.datum` es del tipo `Datum`, que puede ser `InlineDatum(Data)` o `DatumHash(DataHash)`.
- Con `when output.datum is { InlineDatum(_) -> True ... }` distingues ambos casos sin necesidad de librerías externas.
- Los outputs marcados como `InlineDatum` cumplen con CIP-0032 y no requieren que la transacción gastadora provea el datum por separado.

```aiken
use cardano/transaction.{
  OutputReference, Transaction, Output, InlineDatum,
  find_input, find_script_outputs,
}
use aiken/collection/list

pub type Counter {
  count: Int,
}

validator counter_validator {
  spend(
    datum: Option<Counter>,
    _redeemer: Void,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(current) -> {
        // Obtener el hash del script propio a partir del input que se gasta
        expect Some(own_input) =
          find_input(self.inputs, own_ref)
        let own_script_hash =
          own_input.output.address.payment_credential
        // Buscar outputs que regresen al mismo script
        let continuations =
          list.filter(
            self.outputs,
            fn(o: Output) -> Bool {
              o.address.payment_credential == own_script_hash
            },
          )
        // Debe haber exactamente un output de continuación
        when continuations is {
          [continuation] ->
            when continuation.datum is {
              InlineDatum(raw) -> {
                expect new_datum: Counter = raw
                new_datum.count == current.count + 1
              }
              _ -> False
            }
          _ -> False
        }
      }
    }
  }
}
```

**Puntos clave:**
- Se usa `InlineDatum(raw)` para acceder al datum en línea del output de continuación.
- `expect new_datum: Counter = raw` deserializa el `Data` crudo al tipo `Counter`.
- Se verifica que el nuevo `count` sea exactamente `current.count + 1`.
- Se garantiza que hay exactamente un output de continuación al script.

use cardano/assets
use cardano/transaction.{OutputReference, Transaction}
use aiken/collection/list

pub type Datum = Int

validator ref_input_policy_check(required_policy: assets.PolicyId) {
  spend(
    datum: Option<Datum>,
    _redeemer: Void,
