    redeemer: MintRedeemer,
    policy_id: assets.PolicyId,
    self: Transaction,
  ) -> Bool {
    let serialised = builtin.serialise_data(redeemer.payload)
    let expected_name = crypto.blake2b_256(serialised)
    let minted_tokens = assets.tokens(self.mint, policy_id)
    let token_list = assets.flatten(assets.from_asset(policy_id, expected_name, 1))
    let minted_list = assets.flatten(assets.restricted_to(self.mint, [policy_id]))
    and {
      list.length(minted_list) == 1,
      when list.head(minted_list) is {
        None -> False
        Some((_, asset_name, qty)) ->
          asset_name == expected_name && qty == 1
      },
    }
  }
}
```
Este patrón aplica directamente la motivación del CIP-0042: usar `serialiseData` para generar un identificador único (hash del contenido) como nombre del asset, de forma eficiente on-chain.

CIP-0042's `serialiseData` builtin solves the Hydra Head protocol's core problem: needing to verify that two transaction outputs are identical by comparing their CBOR-serialised hashes on-chain. Before this builtin, Hydra had to implement manual CBOR encoding (plutus-cbor), which consumed significant CPU/memory budget scaling linearly with the number of assets in each output.

With `serialiseData`, the pattern becomes trivial and efficient:

```aiken
use aiken/builtin
use aiken/crypto
use cardano/transaction.{OutputReference, Transaction}

// Checks that two arbitrary Data values are equal by comparing their
// blake2b_256 hashes — the Hydra Head pattern for output verification.
fn data_hash_eq(a: Data, b: Data) -> Bool {
  let hash_a = crypto.blake2b_256(builtin.serialise_data(a))
  let hash_b = crypto.blake2b_256(builtin.serialise_data(b))
  hash_a == hash_b
}

validator hydra_output_check {
  spend(
    datum: Option<Data>,
    redeemer: Data,
    _own_ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(stored) -> data_hash_eq(stored, redeemer)
    }
  }
}
```

Key points from CIP-0042:
- `serialiseData` produces the canonical CBOR encoding of any `BuiltinData`/`Data` value.
- Combined with `sha2_256` or `blake2b_256`, it enables content-addressing and integrity verification.
- The cost is now O(1) for the serialisation builtin itself, making transaction size the real bottleneck rather than CPU/memory budget.

