use aiken/collection/list
use cardano/assets
use cardano/transaction.{Transaction}

validator cip68_mint_policy {
  mint(redeemer: Void, policy_id: ByteArray, self: Transaction) -> Bool {
    let ref_label: ByteArray = #"000643b0"
    let user_label: ByteArray = #"000de140"

    // Collect all minted asset names for this policy
    let minted_tokens = assets.tokens(self.mint, policy_id)

    // For every user token minted, assert exactly one matching reference NFT is also minted
    let user_tokens =
      minted_tokens
        |> assets.tokens(policy_id, _)
        // filter names starting with user label

    // Iterate minted pairs and enforce pairing
    assets.reduce(
      self.mint,
      True,
      fn(pid, asset_name, qty, acc) {
        if pid != policy_id {
          acc
        } else {
          // Check if this is a user token
          let is_user =
            builtin.slice_bytearray(0, 4, asset_name) == user_label
          if is_user {
            let base_name = builtin.slice_bytearray(4, builtin.length_of_bytearray(asset_name) - 4, asset_name)
            let ref_name = builtin.append_bytearray(ref_label, base_name)
            let ref_qty = assets.quantity_of(self.mint, policy_id, ref_name)
            // Reference NFT must be minted exactly once
            acc && qty == 1 && ref_qty == 1
          } else {
            acc
          }
        }
      },
    )
  }
}

