use cardano/assets
use cardano/transaction.{Transaction}

const bls12_381_scalar_prime: Int =
  52435875175126190479447740508185965837690552500527637822603658699938581184513

pub type Redeemer {
  field_element: Int,
  claimed_inverse: Int,
}

validator finite_field_mint {
  mint(
    redeemer: Redeemer,
    policy_id: ByteArray,
    self: Transaction,
  ) -> Bool {
    let p = bls12_381_scalar_prime
    let a = redeemer.field_element
    let inv = redeemer.claimed_inverse

    // Check the claimed inverse is valid: a * inv ≡ 1 (mod p)
    let inverse_valid = a * inv % p == 1

    // Check exactly 1 token is minted under this policy
    let minted_tokens = assets.tokens(self.mint, policy_id)
    let total_minted =
      minted_tokens
        |> assets.to_dict
        |> fn(_) { True }
    let mint_count =
      assets.flatten(self.mint)
        |> list.filter(fn(triple) {
            let (pid, _name, qty) = triple
            pid == policy_id && qty == 1
          })
        |> list.length

    inverse_valid && mint_count == 1
  }
}
```

```aiken
use cardano/transaction.{OutputReference, Transaction}

pub type Datum {
  a: Int,
  p: Int,
}

pub type Redeemer {
  inv: Int,
}

/// Checks that `x` is a valid field element: strictly between 0 and p.
fn is_field_element(x: Int, p: Int) -> Bool {
  x > 0 && x < p
}

/// Verifies that `inv` is the multiplicative inverse of `a` in Z/pZ.
fn verify_mod_inverse(a: Int, inv: Int, p: Int) -> Bool {
  is_field_element(a, p) && is_field_element(inv, p) && a * inv % p == 1
}

validator mod_inverse_validator {
  spend(
    datum: Option<Datum>,
    redeemer: Redeemer,
    _own_ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> verify_mod_inverse(d.a, redeemer.inv, d.p)
    }
  }
}
```

Key improvements:
- Extracted `is_field_element` to guard that both `a` and `inv` are in the range `(0, p)`, preventing trivial or invalid inputs.
- Extracted `verify_mod_inverse` for reusability and clarity.
- The core check `a * inv % p == 1` remains as described in CIP-0109 for efficiently verifying a claimed inverse on-chain.

