```aiken
use cardano/transaction.{Transaction, ScriptPurpose, Withdraw, OutputReference}
use cardano/address.{Credential, Script}
use aiken/collection/list
use aiken/crypto.{ScriptHash}

// Validador de gasto que delega la lógica al script observador.
// El observador se identifica por su ScriptHash pasado como parámetro.
validator forwarding_spend(observer_hash: ScriptHash) {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let observer_cred: Credential = Script(observer_hash)
    // Verificar que el observador fue ejecutado en esta transacción
    // buscando su credencial en los redeemers con propósito Withdraw.
    list.any(
      self.redeemers,
      fn(pair) {
        when pair.1st is {
          Withdraw(cred) -> cred == observer_cred
          _ -> False
        }
      },
    )
  }

  else(_) {
    fail
  }
}
```

Este patrón implementa el "token-based forwarding validator" descrito en CIP-0112: el script de gasto no repite lógica propia, sino que verifica que el validador observador (con toda la lógica de negocio) fue ejecutado correctamente en la misma transacción.

