use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use cardano/assets
use cardano/transaction.{Output, OutputReference, Transaction}

pub type SwapDatum {
  owner: VerificationKeyHash,
  required_policy: assets.PolicyId,
  required_asset_name: assets.AssetName,
  required_quantity: Int,
}

validator swap_offer {
  spend(
    datum: Option<SwapDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let owner_signed =
          list.has(self.extra_signatories, d.owner)
        let token_received =
          list.any(
            self.outputs,
            fn(output: Output) -> Bool {
              assets.quantity_of(
                output.value,
                d.required_policy,
                d.required_asset_name,
              ) >= d.required_quantity
            },
          )
        owner_signed || token_received
      }
    }
  }
}
```

