use aiken/builtin
use aiken/collection/list
use cardano/transaction.{OutputReference, Transaction}

pub type AuctionDatum {
  seller_vk: ByteArray,
  auction_id: ByteArray,
}

pub type BidRedeemer {
  bid_price: Int,
  bidder_pkh: ByteArray,
  bidder_signature: ByteArray,
}

fn bidder_signature_message(
  auction_id: ByteArray,
  bid_price: Int,
  bidder_pkh: ByteArray,
) -> ByteArray {
  let price_bytes = builtin.integer_to_bytearray(True, 0, bid_price)
  builtin.append_bytearray(
    auction_id,
    builtin.append_bytearray(price_bytes, bidder_pkh),
  )
}

validator auction_bid {
  spend(
    datum: Option<AuctionDatum>,
    redeemer: BidRedeemer,
    _own_ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let msg =
          bidder_signature_message(
            d.auction_id,
            redeemer.bid_price,
            redeemer.bidder_pkh,
          )
