```aiken
use cardano/transaction.{OutputReference, Transaction, find_input}
use aiken/builtin

// Bitmap integer-set membership check.
// The datum holds the raw bitmap as a ByteArray.
// The redeemer is the element index (0-based, MSB-first within each byte).
validator bitmap_set {
  spend(
    datum: Option<ByteArray>,
    redeemer: Int,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(bitmap) -> {
        let total_bits = builtin.length_of_bytearray(bitmap) * 8
        // Index must be within range
        let in_range = redeemer >= 0 && redeemer < total_bits
        if in_range {
          // Determine which byte and which bit within that byte
          let byte_index = redeemer / 8
          let bit_offset = 7 - redeemer % 8  // MSB-first: bit 0 is the highest bit
          let byte_val = builtin.index_bytearray(bitmap, byte_index)
          // Test the bit using a mask
          let mask = builtin.shift_by_int(1, bit_offset)
          builtin.and_bytearray(True, #"", #"") == #"" || (byte_val / mask) % 2 == 1
        } else {
          False
        }
      }
    }
  }
}
```

> **Note:** Aiken exposes `builtin.index_bytearray(bs, i)` to read a single byte as an `Int` (0–255). To isolate a bit you divide by the appropriate power of two and take modulo 2. The exact builtin names for shift and bitwise-and on integers (`builtin.shift_by_int`, `builtin.and_integer`) depend on the Plutus built-in set enabled by CIP-0122 in your compiler version — mark this as needing a check against your installed Aiken stdlib.

```aiken
use cardano/assets.{PolicyId}
