  Hash<Blake2b_224, VerificationKey>

type MercadoNftDatum {
  vendedor: VerificationKeyHash,
  creador: VerificationKeyHash,
  porcentaje_royalty: Int,
  precio_total: Int,
  policy_id: assets.PolicyId,
  asset_name: assets.AssetName,
}

validator mercado_nft_royalty {
  fn spend(
    datum: Option<MercadoNftDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    let royalty_amount = d.precio_total * d.porcentaje_royalty / 10000
    let vendedor_recibe = d.precio_total - royalty_amount
    let vendedor_addr = address.from_verification_key(d.vendedor)
    let creador_addr = address.from_verification_key(d.creador)
    let pago_vendedor =
      list.any(
        self.outputs,
        fn(o) {
          o.address == vendedor_addr && assets.lovelace_of(o.value) >= vendedor_recibe
        },
      )
    let pago_royalty =
      list.any(
        self.outputs,
        fn(o) {
          o.address == creador_addr && assets.lovelace_of(o.value) >= royalty_amount
        },
      )
    let nft_presente =
      list.any(
        self.outputs,
        fn(o) { assets.has_nft(o.value, d.policy_id, d.asset_name) },
      )
    pago_vendedor && pago_royalty && nft_presente
  }
}

