  nft_name: assets.AssetName,
}

validator royalty_sale {
  fn spend(datum: Option<RoyaltyDatum>, _redeemer: Data, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(d) = datum
    let royalty_amount = d.sale_price * d.royalty_percent / 100
    let seller_amount = d.sale_price - royalty_amount
    let seller_addr = address.from_verification_key(d.seller)
    let creator_addr = address.from_verification_key(d.creator)
    let seller_paid = list.any(self.outputs, fn(o) {
      o.address == seller_addr && assets.lovelace_of(o.value) >= seller_amount
    })
    let royalty_paid = list.any(self.outputs, fn(o) {
      o.address == creator_addr && assets.lovelace_of(o.value) >= royalty_amount
    })
    seller_paid && royalty_paid
  }
}

