use aiken/crypto.{VerificationKeyHash}

validator cosigned_batch_mint(
  operator: VerificationKeyHash,
  cosigner: VerificationKeyHash,
  asset_name: ByteArray,
  batch_size: Int,
) {
  fn mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) -> Bool {
    let operator_signed = list.has(self.extra_signatories, operator)
    let cosigner_signed = list.has(self.extra_signatories, cosigner)
    let qty = assets.quantity_of(self.mint, policy_id, asset_name)
    operator_signed && cosigner_signed && qty == batch_size
  }
}

use cardano/assets
use cardano/transaction.{Transaction, PolicyId}
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use aiken/interval

validator timed_mint_free_burn(
  admin: VerificationKeyHash,
  asset_name: ByteArray,
  mint_open: Int,
  mint_close: Int,
) {
  fn mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) -> Bool {
    let is_authorized = list.has(self.extra_signatories, admin)
    let qty = assets.quantity_of(self.mint, policy_id, asset_name)
    if qty < 0 {
      is_authorized
    } else {
      let in_window =
        interval.is_entirely_after(self.validity_range, mint_open) && interval.is_entirely_before(self.validity_range, mint_close)
      is_authorized && in_window && qty > 0
    }
  }
}

use aiken/collection/dict
use aiken/collection/list
use cardano/assets
use cardano/transaction.{OutputReference, Transaction}

validator one_shot(utxo_ref: OutputReference) {
  fn mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) -> Bool {
    let Transaction { inputs, mint, .. } = self
    let is_utxo_consumed =
      list.any(inputs, fn(input) { input.output_reference == utxo_ref })
    expect [Pair(_asset_name, quantity)] =
      mint
        |> assets.tokens(policy_id)
        |> dict.to_pairs()
    is_utxo_consumed && quantity == 1
  }

  else(_) {
    fail
  }
}

