validator one_shot_nft(utxo_ref: OutputReference) {
  fn mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) -> Bool {
    let Transaction { inputs, mint, .. } = self
    let is_utxo_consumed =
      list.any(inputs, fn(i) { i.output_reference == utxo_ref })
    expect Some(first_input) = list.at(inputs, 0)
    let expected_name =
      first_input.output_reference
        |> cbor.serialise
        |> builtin.blake2b_256
    expect [Pair(asset_name, quantity)] =
      mint
        |> assets.tokens(policy_id)
        |> dict.to_pairs()
    is_utxo_consumed && asset_name == expected_name && quantity == 1
  }

  else(_) {
    fail
  }
}

