pub type RetiroGobernanzaRedeemer {
  administradores: List<VerificationKeyHash>,
  quorum: Int,
  plazo_votacion: Int,
}

validator retiro_dao_gobernanza {
  fn withdraw(
    redeemer: RetiroGobernanzaRedeemer,
    _cuenta: Credential,
    self: Transaction,
  ) -> Bool {
    let votos =
      list.count(
        redeemer.administradores,
        fn(k) { list.has(self.extra_signatories, k) },
      )
    let quorum_alcanzado = votos >= redeemer.quorum
    let despues_plazo =
      interval.is_entirely_after(
        self.validity_range,
        redeemer.plazo_votacion,
      )
    quorum_alcanzado && despues_plazo
  }
}

