pub type TokenGateRedeemer {
  gov_policy: PolicyId,
  gov_asset: AssetName,
  min_tokens: Int,
}

validator token_gated_withdrawal {
  fn withdraw(
    redeemer: TokenGateRedeemer,
    _account: Credential,
    self: Transaction,
  ) -> Bool {
    list.any(
      self.inputs,
      fn(input) {
        assets.quantity_of(
          input.output.value,
          redeemer.gov_policy,
          redeemer.gov_asset,
        ) >= redeemer.min_tokens
      },
    )
  }
}

use aiken/collection/list
