use cardano/transaction.{Transaction}

pub type FeeWithdrawRedeemer {
  owner: VerificationKeyHash,
  treasury_address: Address,
  protocol_fee: Int,
}

validator fee_enforced_withdrawal {
  fn withdraw(
    redeemer: FeeWithdrawRedeemer,
    _account: Credential,
    self: Transaction,
  ) -> Bool {
    let signed = list.has(self.extra_signatories, redeemer.owner)
    let fee_paid =
      list.any(
        self.outputs,
        fn(output) {
          output.address == redeemer.treasury_address && assets.lovelace_of(
            output.value,
          ) >= redeemer.protocol_fee
        },
      )
    signed && fee_paid
  }
}

