type VerificationKeyHash = Hash<Blake2b_224, VerificationKey>

pub type Datum {
  recipient: VerificationKeyHash,
  min_total: Int,
}

validator total_to_recipient {
  fn spend(
    optional_datum: Option<Datum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(datum) = optional_datum
    let recipient_addr = address.from_verification_key(datum.recipient)
    let matching = list.filter(self.outputs, fn(o) { o.address == recipient_addr })
    let total =
      list.foldl(
        matching,
        0,
        fn(o, acc) { acc + assets.lovelace_of(o.value) },
      )
    total >= datum.min_total
  }
}

