validator script_outputs_have_inline_datum {
  fn spend(
    optional_datum: Option<Datum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(datum) = optional_datum
    let script_addr = address.from_script(datum.script)
    let script_outputs =
      list.filter(self.outputs, fn(o) { o.address == script_addr })
    list.all(
      script_outputs,
      fn(o) {
        when o.datum is {
          InlineDatum(_) -> True
          _ -> False
        }
      },
    )
  }
}

