    optional_datum: Option<Datum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(datum) = optional_datum
    let amounts =
      list.map(self.outputs, fn(o) { assets.lovelace_of(o.value) })
