type VerificationKeyHash =
  Hash<Blake2b_224, VerificationKey>

type VentaNftDatum {
  vendedor: VerificationKeyHash,
  creador: VerificationKeyHash,
  precio: Int,
  royalty_bps: Int,
}

type VentaRedeemer {
  Comprar
}

validator venta_nft_royalty {
  fn spend(
    datum: Option<VentaNftDatum>,
    redeemer: VentaRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Comprar -> {
        let royalty_amount = d.precio * d.royalty_bps / 10000
        let seller_amount = d.precio - royalty_amount
        let addr_vendedor = address.from_verification_key(d.vendedor)
        let addr_creador = address.from_verification_key(d.creador)
        let seller_paid =
          list.any(
            self.outputs,
            fn(o) {
              o.address == addr_vendedor
                && assets.lovelace_of(o.value) >= seller_amount
            },
          )
        let royalty_paid =
          list.any(
            self.outputs,
            fn(o) {
              o.address == addr_creador
                && assets.lovelace_of(o.value) >= royalty_amount
            },
          )
        seller_paid && royalty_paid
      }
    }
  }
}

