}

type RewardRedeemer {
  ClaimReward
  RevokeReward
}

validator game_reward_vault {
  fn spend(
    datum: Option<RewardDatum>,
    redeemer: RewardRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      ClaimReward -> {
        let winner_addr = address.from_verification_key(d.winner)
        list.has(self.extra_signatories, d.winner)
          && list.any(
               self.outputs,
               fn(o) {
                 o.address == winner_addr
                   && assets.lovelace_of(o.value) >= d.reward
               },
             )
