      Reembolsar ->
        list.has(self.extra_signatories, d.vendedor)
          && list.has(self.extra_signatories, d.comprador)
      Arbitrar ->
        interval.is_entirely_after(self.validity_range, d.limite)
          && list.has(self.extra_signatories, d.arbitro)
    }
  }
}

